<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Maze Bots</title>
<style>
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body {
    background: linear-gradient(135deg, #0f0f23 0%, #1a1a3e 50%, #16213e 100%);
    color: #e0e0e0;
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
    display: flex;
    flex-direction: column;
    align-items: center;
    min-height: 100vh;
    padding: 20px;
  }
  h1 {
    margin-bottom: 16px;
    font-size: 30px;
    font-weight: 700;
    background: linear-gradient(90deg, #e94560, #ffd700, #4ade80);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
    letter-spacing: 1px;
  }
  #hud {
    display: flex;
    gap: 16px;
    margin-bottom: 20px;
    flex-wrap: wrap;
    justify-content: center;
  }
  #hud > div {
    background: rgba(15, 52, 96, 0.5);
    padding: 10px 20px;
    border-radius: 10px;
    border: 1px solid rgba(233, 69, 96, 0.4);
    font-size: 15px;
    font-weight: 500;
    min-width: 150px;
    text-align: center;
  }
  #hud span {
    color: #ffd700;
    font-weight: 700;
    font-variant-numeric: tabular-nums;
  }
  #maze {
    background: #0a0a1e;
    border: 3px solid #e94560;
    border-radius: 6px;
    display: block;
    box-shadow: 0 0 40px rgba(233, 69, 96, 0.25), inset 0 0 20px rgba(0,0,0,0.5);
  }
  #reset {
    margin-top: 20px;
    padding: 12px 36px;
    background: linear-gradient(90deg, #e94560, #c23152);
    color: white;
    border: none;
    border-radius: 10px;
    cursor: pointer;
    font-size: 16px;
    font-weight: 600;
    letter-spacing: 0.5px;
    transition: transform 0.15s, box-shadow 0.2s;
    box-shadow: 0 4px 12px rgba(233, 69, 96, 0.3);
  }
  #reset:hover {
    transform: translateY(-2px);
    box-shadow: 0 6px 16px rgba(233, 69, 96, 0.5);
  }
  #reset:active { transform: translateY(0); }
</style>
</head>
<body>
<h1>🤖 Maze Bots</h1>
<div id="hud">
  <div>Completed: <span id="completed">0</span> / 24</div>
  <div>Time: <span id="timer">0.0</span>s</div>
</div>
<canvas id="maze" width="462" height="462"></canvas>
<button id="reset">🔄 Reset Game</button>
<script>
(function() {
  'use strict';

  const COLS = 21;
  const ROWS = 21;
  const CELL = 22;
  const BOT_COUNT = 24;
  const MS_PER_TICK = 16;

  const canvas = document.getElementById('maze');
  const ctx = canvas.getContext('2d');
  canvas.width = COLS * CELL;
  canvas.height = ROWS * CELL;

  const completedEl = document.getElementById('completed');
  const timerEl = document.getElementById('timer');
  const resetBtn = document.getElementById('reset');

  let maze = [];
  const SPAWN = { x: 0, y: 0 };
  const EXIT = { x: COLS - 1, y: ROWS - 1 };

  // Wall bitmask: N=1, E=2, S=4, W=8
  function generateMaze() {
    maze = [];
    for (let y = 0; y < ROWS; y++) {
      const row = [];
      for (let x = 0; x < COLS; x++) {
        row.push({ walls: 15, visited: false });
      }
      maze.push(row);
    }

    const stack = [[SPAWN.x, SPAWN.y]];
    maze[SPAWN.y][SPAWN.x].visited = true;

    while (stack.length > 0) {
      const [x, y] = stack[stack.length - 1];
      const neighbors = [];
      // dir: 0=N, 1=E, 2=S, 3=W
      if (y > 0 && !maze[y-1][x].visited) neighbors.push([x, y-1, 0]);
      if (x < COLS-1 && !maze[y][x+1].visited) neighbors.push([x+1, y, 1]);
      if (y < ROWS-1 && !maze[y+1][x].visited) neighbors.push([x, y+1, 2]);
      if (x > 0 && !maze[y][x-1].visited) neighbors.push([x-1, y, 3]);

      if (neighbors.length === 0) {
        stack.pop();
        continue;
      }

      const [nx, ny, dir] = neighbors[Math.floor(Math.random() * neighbors.length)];
      const myWallBit = 1 << dir;
      const theirWallBit = 1 << ((dir + 2) % 4);
      maze[y][x].walls &= ~myWallBit;
      maze[ny][nx].walls &= ~theirWallBit;

      maze[ny][nx].visited = true;
      stack.push([nx, ny]);
    }
  }

  function bfs(start, end) {
    const visited = Array.from({length: ROWS}, () => Array(COLS).fill(false));
    const parent = Array.from({length: ROWS}, () => Array(COLS).fill(null));
    const queue = [[start.x, start.y]];
    let head = 0;
    visited[start.y][start.x] = true;

    while (head < queue.length) {
      const [x, y] = queue[head++];
      if (x === end.x && y === end.y) {
        const path = [];
        let cur = [end.x, end.y];
        while (cur) {
          path.unshift(cur);
          cur = parent[cur[1]][cur[0]];
        }
        return path;
      }

      const walls = maze[y][x].walls;
      if (!(walls & 1) && y > 0 && !visited[y-1][x]) {
        visited[y-1][x] = true;
        parent[y-1][x] = [x, y];
        queue.push([x, y-1]);
      }
      if (!(walls & 2) && x < COLS-1 && !visited[y][x+1]) {
        visited[y][x+1] = true;
        parent[y][x+1] = [x, y];
        queue.push([x+1, y]);
      }
      if (!(walls & 4) && y < ROWS-1 && !visited[y+1][x]) {
        visited[y+1][x] = true;
        parent[y+1][x] = [x, y];
        queue.push([x, y+1]);
      }
      if (!(walls & 8) && x > 0 && !visited[y][x-1]) {
        visited[y][x-1] = true;
        parent[y][x-1] = [x, y];
        queue.push([x-1, y]);
      }
    }
    return null;
  }

  let bots = [];
  let completed = 0;
  let currentTick = 0;
  let elapsedMs = 0;
  let lastFrameTime = null;
  let animFrame = null;
  let running = false;

  function initBots() {
    generateMaze();
    const path = bfs(SPAWN, EXIT);
    if (!path) {
      console.error('No path found!');
      return;
    }

    bots = [];
    completed = 0;
    currentTick = 0;
    elapsedMs = 0;
    lastFrameTime = null;

    for (let i = 0; i < BOT_COUNT; i++) {
      const startDelay = Math.floor(Math.random() * 100);
      const moveInterval = 1 + Math.floor(Math.random() * 3);
      const px = path[0][0] * CELL + CELL / 2;
      const py = path[0][1] * CELL + CELL / 2;
      bots.push({
        x: path[0][0],
        y: path[0][1],
        renderX: px,
        renderY: py,
        path: path,
        pathIndex: 0,
        nextMoveTick: startDelay,
        moveInterval: moveInterval,
        completed: false,
        color: `hsl(${(i * 15 + 180) % 360}, 85%, 62%)`,
        pulse: Math.random() * Math.PI * 2
      });
    }

    updateHUD();
  }

  function tick(n) {
    for (let step = 0; step < n; step++) {
      currentTick++;
      for (let i = 0; i < bots.length; i++) {
        const bot = bots[i];
        if (bot.completed) continue;
        if (currentTick >= bot.nextMoveTick) {
          bot.pathIndex++;
          if (bot.pathIndex >= bot.path.length) {
            bot.x = bot.path[bot.path.length - 1][0];
            bot.y = bot.path[bot.path.length - 1][1];
            bot.completed = true;
            completed++;
          } else {
            bot.x = bot.path[bot.pathIndex][0];
            bot.y = bot.path[bot.pathIndex][1];
            bot.nextMoveTick = currentTick + bot.moveInterval;
          }
        }
      }
    }
    elapsedMs += n * MS_PER_TICK;
    updateHUD();
  }

  function reset() {
    running = false;
    if (animFrame) {
      cancelAnimationFrame(animFrame);
      animFrame = null;
    }
    initBots();
    render();
    running = true;
    animFrame = requestAnimationFrame(loop);
  }

  function updateHUD() {
    completedEl.textContent = completed;
    timerEl.textContent = (elapsedMs / 1000).toFixed(1);
  }

  function render() {
    ctx.fillStyle = '#0a0a1e';
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    // Draw cells
    for (let y = 0; y < ROWS; y++) {
      for (let x = 0; x < COLS; x++) {
        const cell = maze[y][x];
        const px = x * CELL;
        const py = y * CELL;

        // Cell background
        if (x === SPAWN.x && y === SPAWN.y) {
          ctx.fillStyle = '#1a3a1a';
        } else if (x === EXIT.x && y === EXIT.y) {
          ctx.fillStyle = '#3a2a1a';
        } else {
          ctx.fillStyle = '#16213e';
        }
        ctx.fillRect(px + 1, py + 1, CELL - 2, CELL - 2);

        // Walls
        ctx.strokeStyle = '#e94560';
        ctx.lineWidth = 2;
        ctx.lineCap = 'square';
        ctx.beginPath();
        if (cell.walls & 1) { ctx.moveTo(px, py); ctx.lineTo(px + CELL, py); }
        if (cell.walls & 2) { ctx.moveTo(px + CELL, py); ctx.lineTo(px + CELL, py + CELL); }
        if (cell.walls & 4) { ctx.moveTo(px, py + CELL); ctx.lineTo(px + CELL, py + CELL); }
        if (cell.walls & 8) { ctx.moveTo(px, py); ctx.lineTo(px, py + CELL); }
        ctx.stroke();
      }
    }

    // Exit glow
    const exitPulse = 0.5 + Math.sin(performance.now() / 300) * 0.3;
    ctx.fillStyle = `rgba(255, 215, 0, ${exitPulse * 0.3})`;
    ctx.beginPath();
    ctx.arc(EXIT.x * CELL + CELL / 2, EXIT.y * CELL + CELL / 2, CELL * 0.8, 0, Math.PI * 2);
    ctx.fill();

    // Exit marker
    ctx.fillStyle = '#ffd700';
    ctx.font = 'bold 18px sans-serif';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.fillText('★', EXIT.x * CELL + CELL / 2, EXIT.y * CELL + CELL / 2 + 1);

    // Spawn marker
    ctx.fillStyle = '#4ade80';
    ctx.font = 'bold 14px sans-serif';
    ctx.fillText('▶', SPAWN.x * CELL + CELL / 2, SPAWN.y * CELL + CELL / 2 + 1);

    // Draw bots
    const time = performance.now() / 1000;
    for (const bot of bots) {
      const pulseScale = 1 + Math.sin(time * 3 + bot.pulse) * 0.12;
      const radius = (CELL / 3.5) * pulseScale;

      // Outer glow
      ctx.fillStyle = bot.color + '25';
      ctx.beginPath();
      ctx.arc(bot.renderX, bot.renderY, CELL / 2.2, 0, Math.PI * 2);
      ctx.fill();

      // Body
      ctx.fillStyle = bot.color;
      ctx.beginPath();
      ctx.arc(bot.renderX, bot.renderY, radius, 0, Math.PI * 2);
      ctx.fill();

      // Border
      ctx.strokeStyle = 'rgba(255,255,255,0.35)';
      ctx.lineWidth = 1;
      ctx.stroke();

      // Highlight
      ctx.fillStyle = 'rgba(255,255,255,0.55)';
      ctx.beginPath();
      ctx.arc(bot.renderX - CELL / 14, bot.renderY - CELL / 14, CELL / 10, 0, Math.PI * 2);
      ctx.fill();
    }
  }

  function loop(time) {
    if (!running) return;

    if (lastFrameTime === null) lastFrameTime = time;
    const dt = Math.min(50, time - lastFrameTime);
    lastFrameTime = time;

    tick(1);

    // Interpolate render positions for smooth animation
    const lerpSpeed = Math.min(1, dt / (MS_PER_TICK * 1.2));
    for (const bot of bots) {
      const targetX = bot.x * CELL + CELL / 2;
      const targetY = bot.y * CELL + CELL / 2;
      bot.renderX += (targetX - bot.renderX) * lerpSpeed;
      bot.renderY += (targetY - bot.renderY) * lerpSpeed;
    }

    render();

    if (completed < BOT_COUNT) {
      animFrame = requestAnimationFrame(loop);
    } else {
      animFrame = null;
    }
  }

  resetBtn.addEventListener('click', reset);

  window.game = {
    get bots() { return bots; },
    get completed() { return completed; },
    get elapsedMs() { return elapsedMs; },
    tick: tick,
    reset: reset
  };

  reset();
})();
</script>
</body>
</html>
